// Cocos 前向渲染管线的 Flow 布局示例
// RenderPipeline
//   +-- ForwardFlow (priority: 0)
//   |   +-- ShadowStage (priority: 0)      -- 渲染阴影贴图
//   |   +-- GBufferStage (priority: 1)     -- 渲染 G-Buffer（延迟管线）
//   |   +-- LightingStage (priority: 2)    -- 光照计算
//   |   +-- BloomStage (priority: 3)       -- Bloom 后处理
//   |   +-- UIPresentStage (priority: 4)   -- UI 渲染
//   +-- UIFlow (priority: 1)
//       +-- UIStage (priority: 0)          -- 2D UI 渲染
